class Foo {
    fun bad() {
        try {
            doSomething()
        } catch (e: Exception) {
            throw RuntimeException("msg")
        }
    }
    private fun doSomething() {}
}

class Foo {
    fun bad() {
        try {
            doSomething()
        } catch (e: Exception) {
            throw RuntimeException(e.message)
        }
    }
    private fun doSomething() {}
}

class Foo {
    fun good() {
        try {
            doSomething()
        } catch (e: Exception) {
            throw RuntimeException(e)
        }
    }
    private fun doSomething() {}
}

class Foo {
    fun good() {
        try {
            doSomething()
        } catch (e: Exception) {
            throw RuntimeException("msg", e)
        }
    }
    private fun doSomething() {}
}

class Foo {
    fun good() {
        try {
            doSomething()
        } catch (ignoredException: Exception) {
            throw RuntimeException("expected failure")
        }
    }
    private fun doSomething() {}
}

class Foo {
    fun good() {
        try {
            doSomething()
        } catch (_: Exception) {
            throw RuntimeException("expected failure")
        }
    }
    private fun doSomething() {}
}

class Foo {
    fun good() {
        try {
            doSomething()
        } catch (e: Exception) {
            throw e
        }
    }
    private fun doSomething() {}
}

class Foo {
    fun good() {
        try {
            doSomething()
        } catch (e: IllegalStateException) {
            throw e
        } catch (e: Exception) {
            throw RuntimeException("wrapped", e)
        }
    }
    private fun doSomething() {}
}
